def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function now builds mission‑centric sentences
    that combine commander, backup pilot and crew members into a single clause,
    then falls back to the original subject‑centric handling for any remaining
    triples.
    """
    if not triples:
        return ""

    # ----------------------------------------------------------------------
    # Helper: turn a predicate/object pair into a descriptor for generic subjects
    # ----------------------------------------------------------------------
    def phrase(subj: str, pred: str, obj: str) -> str:
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                return "American"
            if low_obj.startswith("the "):
                return obj[4:].strip()
            return obj
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # astronaut -> mission link, will be handled later
            return f"was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "leader":
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # ----------------------------------------------------------------------
    # First pass: collect mission‑centric information
    # ----------------------------------------------------------------------
    mission_info = {}
    used_triples = set()   # indices of triples that will be consumed by mission handling

    for idx, t in enumerate(triples):
        pred = t.predicate.lower().replace(" ", "")
        if pred == "mission":
            # astronaut -> mission
            mission = t.object.strip().strip('"')
            mission_entry = mission_info.setdefault(mission, {"commander": None,
                                                             "backupPilot": None,
                                                             "crew": []})
            mission_entry["crew"].append(t.subject)
            used_triples.add(idx)
        elif pred == "commander":
            mission = t.subject
            mission_entry = mission_info.setdefault(mission, {"commander": None,
                                                             "backupPilot": None,
                                                             "crew": []})
            mission_entry["commander"] = t.object
            used_triples.add(idx)
        elif pred == "backuppilot":
            mission = t.subject
            mission_entry = mission_info.setdefault(mission, {"commander": None,
                                                             "backupPilot": None,
                                                             "crew": []})
            mission_entry["backupPilot"] = t.object
            used_triples.add(idx)
        elif pred == "crewmembers":
            mission = t.subject
            mission_entry = mission_info.setdefault(mission, {"commander": None,
                                                             "backupPilot": None,
                                                             "crew": []})
            mission_entry["crew"].append(t.object)
            used_triples.add(idx)

    sentences = []

    # ----------------------------------------------------------------------
    # Build sentences for each mission
    # ----------------------------------------------------------------------
    for mission, data in mission_info.items():
        parts = []
        if data["commander"]:
            parts.append(f"Commander {data['commander']}")
        if data["crew"]:
            # ensure commander not duplicated in crew list
            crew_names = [c for c in data["crew"] if c != data["commander"]]
            if crew_names:
                crew_str = ", ".join(crew_names)
                parts.append(f"crew members {crew_str}")
        if data["backupPilot"]:
            parts.append(f"backup pilot {data['backupPilot']}")
        if parts:
            # join with commas and 'and' before the last
            if len(parts) == 1:
                mission_clause = parts[0]
            else:
                mission_clause = ", ".join(parts[:-1]) + f", and {parts[-1]}"
            sentences.append(f"{mission}: {mission_clause}.")
        # Remove used triples from further processing
        # (We'll filter them out when handling the remaining subjects)

    # ----------------------------------------------------------------------
    # Handle remaining triples (those not used in mission‑centric processing)
    # ----------------------------------------------------------------------
    from collections import defaultdict
    groups = defaultdict(list)
    for idx, t in enumerate(triples):
        if idx in used_triples:
            continue
        groups[t.subject].append(t)

    for subj, items in groups.items():
        descriptors = [phrase(subj, t.predicate, t.object) for t in items]
        if not descriptors:
            sentences.append(f"{subj}.")
            continue
        if len(descriptors) == 1:
            sentences.append(f"{subj} {descriptors[0]}.")
        else:
            body = ", ".join(descriptors[:-1])
            sentences.append(f"{subj} {body}, and {descriptors[-1]}.")

    # Combine all sentences
    return " ".join(sentences)

# EVOLVE-BLOCK-END

